--line);border-radius:18px;box-shadow:0 8px 25px rgba(35,57,86,.045);overflow:hidden}.accordion-head{display:flex;align-items:center;justify-content:space-between;gap:16px;padding:22px 24px;cursor:pointer;list-style:none}.accordion-head::-webkit-details-marker{display:none}.accordion-copy h2{margin:0;font-size:20px}.accordion-copy p{margin:5px 0 0;color:var(--muted);font-size:14px}.card:not([open]) .accordion-copy p{display:none}.accordion-meta{display:flex;align-items:center;gap:12px}.accordion-arrow{font-size:22px;color:var(--muted);transition:.2s}.card[open] .accordion-arrow{transform:rotate(180deg)}.accordion-body{padding:0 24px 24px;border-top:1px solid var(--line)}.status-icon{width:22px;height:22px;display:inline-grid;place-items:center;border-radius:50%;color:#fff;font-size:13px;font-weight:900}.status-icon.ok{background:var(--green)}.status-icon.warn{background:var(--amber)}.status-icon.error{background:var(--red)}.field{margin-top:15px}.field label{display:block;margin-bottom:7px;font-size:14px;font-weight:700}.input{width:100%;padding:13px 14px;border:1px solid #dbe3ed;border-radius:11px;background:#fbfcfe;color:var(--text);font:inherit}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:44px;padding:11px 16px;border:0;border-radius:10px;background:var(--blue);color:#fff;font-weight:750;cursor:pointer}.btn.secondary{background:#eef4fd;color:var(--blue)}.btn.danger{background:#fff0f0;color:var(--red)}.actions{display:flex;flex-wrap:wrap;gap:10px;margin-top:18px}.savebar,.toolbar{display:flex;justify-content:flex-end;margin-top:18px}.flash,.errors,.notice,.inline-error{margin-bottom:18px;padding:13px 15px;border-radius:11px}.flash{background:#eaf8f1;color:#13764b}.errors,.inline-error{background:#fff0f0;color:#a72d2d}.notice{background:#fff6e6;color:#8b5d10}.list{display:grid;gap:10px;margin-top:16px}.row{border:1px solid var(--line);border-radius:14px;background:#fbfcfe;overflow:hidden}.row-main{display:grid;grid-template-columns:minmax(180px,1.4fr) minmax(180px,1fr) auto;gap:14px;align-items:center;padding:15px 16px;cursor:pointer}.row-name{font-weight:800}.row-meta{font-size:13px;color:var(--muted);word-break:break-word}.badge{display:inline-block;margin-left:7px;padding:3px 7px;border-radius:999px;background:#eaf1ff;color:var(--blue);font-size:11px;font-weight:800}.row-status{justify-self:end}.row-panel{display:none;padding:0 16px 16px;border-top:1px solid var(--line)}.row.active .row-panel{display:block}.add-form{display:none;margin-top:14px;padding:16px;border:1px dashed #b9c7da;border-radius:14px;background:#f8fafc}.add-form.open{display:block}.switch-row{display:flex;align-items:center;justify-content:space-between;gap:20px;padding:15px 0;border-bottom:1px solid var(--line)}.switch{position:relative;width:52px;height:30px}.switch input{opacity:0}.slider{position:absolute;inset:0;border-radius:30px;background:#cfd7e2}.slider:before{content:"";position:absolute;width:24px;height:24px;left:3px;top:3px;border-radius:50%;background:#fff;transition:.2s}.switch input:checked+.slider{background:var(--blue)}.switch input:checked+.slider:before{transform:translateX(22px)}.summary{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px;margin-top:16px}.summary-item{padding:16px;border-radius:13px;background:#f8fafc}.summary-item span{display:block;color:var(--muted);font-size:12px}.summary-item strong{display:block;margin-top:7px;font-size:14px}.overlay{display:none}@media(max-width:800px){.app{display:block}.sidebar{position:fixed;left:0;top:0;width:292px;transform:translateX(-105%);transition:.22s;z-index:30}body.menu-open .sidebar{transform:translateX(0)}.overlay{display:block;position:fixed;inset:0;background:rgba(2,10,23,.52);opacity:0;pointer-events:none;z-index:20}body.menu-open .overlay{opacity:1;pointer-events:auto}.main{padding:20px 16px}.menu-btn{display:grid;place-items:center}.heading h1{font-size:29px}.summary{grid-template-columns:1fr}.row-main{grid-template-columns:1f